  1→use agentrail_core::error::Result;
  2→use agentrail_core::{SagaStatus, StepRole, StepStatus, Trajectory};
  3→use agentrail_store::{saga, session, step, trajectory};
  4→use std::path::Path;
  5→
  6→pub struct CompleteArgs<'a> {
  7→    pub summary: Option<&'a str>,
  8→    pub next_slug: Option<&'a str>,
  9→    pub next_prompt: Option<&'a str>,
 10→    pub next_context: Vec<String>,
 11→    pub next_role: &'a str,
 12→    pub next_task_type: Option<&'a str>,
 13→    pub planned: Vec<String>,
 14→    pub done: bool,
 15→    /// Reward for this step's trajectory (-1, 0, or 1)
 16→    pub reward: Option<i8>,
 17→    /// Description of actions taken (for trajectory recording)
 18→    pub actions: Option<&'a str>,
 19→    /// Failure mode identifier (for trajectory recording on failure)
 20→    pub failure_mode: Option<&'a str>,
 21→}
 22→
 23→pub fn run(saga_path: &Path, args: &CompleteArgs<'_>) -> Result<()> {
 24→    let mut config = saga::load_saga(saga_path)?;
 25→    let saga_dir = saga::saga_dir(saga_path);
 26→
 27→    // Try to snapshot session (non-fatal, silent when no session exists)
 28→    if let Ok((path, lines)) = session::snapshot_session(&saga_dir, saga_path)
 29→        && lines > 0
 30→    {
 31→        eprintln!("Snapshotted {} new lines to {}", lines, path.display());
 32→    }
 33→
 34→    // Read summary
 35→    let summary_text = match args.summary {
 36→        Some(raw) => agentrail_core::read_input(raw)?,
 37→        None => String::new(),
 38→    };
 39→
 40→    // Complete current step (or handle step 0)
 41→    if config.current_step == 0 {
 42→        if !summary_text.is_empty() {
 43→            let summary_path = saga_dir.join("step0-summary.md");
 44→            std::fs::write(&summary_path, &summary_text)?;
 45→            println!("Saved step 0 summary.");
 46→        }
 47→    } else {
 48→        let step_dir = step::find_step_dir(&saga_dir, config.current_step)?;
 49→        let mut step_config = step::load_step(&step_dir)?;
 50→
 51→        // Auto-begin if still pending
 52→        if step_config.status == StepStatus::Pending {
 53→            step::transition_step(&mut step_config, StepStatus::InProgress)?;
 54→        }
 55→
 56→        step::transition_step(&mut step_config, StepStatus::Completed)?;
 57→        step::save_step(&step_dir, &step_config)?;
 58→
 59→        if !summary_text.is_empty() {
 60→            step::save_summary(&step_dir, &summary_text)?;
 61→        }
 62→
 63→        // Record trajectory if step has a task_type and reward is provided
 64→        if let Some(ref task_type) = step_config.task_type {
 65→            let reward = args.reward.unwrap_or(1);
 66→            let action = args
 67→                .actions
 68→                .map(|s| s.to_string())
 69→                .unwrap_or_else(|| summary_text.clone());
 70→            let result = if reward > 0 {
 71→                "success".to_string()
 72→            } else if let Some(fm) = args.failure_mode {
 73→                format!("failure: {fm}")
 74→            } else {
 75→                "failure".to_string()
 76→            };
 77→
 78→            let t = Trajectory {
 79→                task_type: task_type.clone(),
 80→                state: serde_json::json!({"step": step_config.slug, "number": step_config.number}),
 81→                action,
 82→                result,
 83→                reward,
 84→                timestamp: agentrail_core::timestamp_iso(),
 85→            };
 86→            let path = trajectory::save_trajectory(&saga_dir, &t)?;
 87→            println!(
 88→                "Recorded trajectory for '{}' (reward={:+}) at {}",
 89→                task_type,
 90→                reward,
 91→                path.display()
 92→            );
 93→        }
 94→
 95→        println!(
 96→            "Completed step {:03}-{}.",
 97→            step_config.number, step_config.slug
 98→        );
 99→    }
100→

 1→//! COR24 ISA definitions shared between compiler and assembler/emulator.
 2→//!
 3→//! This crate defines the canonical instruction set, encoding tables,
 4→//! register names, and branch range constants for the COR24 architecture.
 5→
 6→pub mod branch;
 7→pub mod encode;
 8→pub mod opcode;
 9→pub mod register;
10→
11→pub use branch::{BRANCH_OFFSET_MAX, BRANCH_OFFSET_MIN, BRANCH_PIPELINE_DELAY, MAX_INSTRUCTION_BYTES};
12→pub use opcode::{DecodedInstruction, InstructionFormat, Opcode};
13→pub use register::{REG_NAMES, reg_name};
