102→/// A single instruction execution record
103→#[derive(Clone, Debug)]
104→pub struct TraceEntry {
105→    /// Program counter at start of instruction
106→    pub pc: u32,
107→    /// Decoded opcode
108→    pub opcode: Opcode,
109→    /// Destination register index
110→    pub ra: u8,
111→    /// Source register index
112→    pub rb: u8,
113→    /// Instruction size in bytes (1, 2, or 4)
114→    pub size: u8,
115→    /// 8-bit immediate (for 2-byte and 4-byte instructions)
116→    pub imm8: u8,
117→    /// 24-bit immediate (for 4-byte instructions)
118→    pub imm24: u32,
119→    /// Register state before execution
120→    pub regs_before: [u32; 8],
121→    /// Register state after execution
122→    pub regs_after: [u32; 8],
123→    /// Condition flag before
124→    pub c_before: bool,
125→    /// Condition flag after
126→    pub c_after: bool,
127→    /// SP before (convenience, same as regs_before\[4\])
128→    pub sp_before: u32,
129→    /// Instruction count at this point
130→    pub instruction_num: u64,
131→}
132→
133→/// Register names for display
134→const REG_NAMES: [&str; 8] = ["r0", "r1", "r2", "fp", "sp", "z/c", "iv", "ir"];
135→
136→impl fmt::Display for TraceEntry {
137→    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
138→        // Disassemble the instruction
139→        let disasm = self.disassemble();
140→
141→        write!(f, "{:5} 0x{:06X}  {:<24}", self.instruction_num, self.pc, disasm)?;
142→
143→        // Show register changes
144→        let mut changes = Vec::new();
145→        for (i, name) in REG_NAMES.iter().enumerate() {
146→            if self.regs_before[i] != self.regs_after[i] {
147→                changes.push(format!("{}:0x{:06X}→0x{:06X}",
148→                    name, self.regs_before[i], self.regs_after[i]));
149→            }
150→        }
151→        if self.c_before != self.c_after {
152→            changes.push(format!("c:{}→{}", self.c_before as u8, self.c_after as u8));
153→        }
154→        if !changes.is_empty() {
155→            write!(f, "  [{}]", changes.join(" "))?;
156→        }
157→
158→        Ok(())
159→    }
160→}
161→
162→impl TraceEntry {
163→    /// Disassemble this instruction into a human-readable string
164→    pub fn disassemble(&self) -> String {
165→        let ra = REG_NAMES[self.ra as usize];
166→        let rb = REG_NAMES[self.rb as usize];
167→        match self.opcode {
168→            Opcode::AddReg => format!("add     {},{}", ra, rb),
169→            Opcode::AddImm => format!("add     {},{}", ra, self.imm8 as i8),
170→            Opcode::And => format!("and     {},{}", ra, rb),
171→            Opcode::Bra => {
172→                let offset = self.imm8 as i8;
173→                let target = (self.pc as i64 + 4 + offset as i64) as u32 & 0xFFFFFF;
174→                format!("bra     0x{:06X}", target)
175→            }
176→            Opcode::Brf => {
177→                let offset = self.imm8 as i8;
178→                let target = (self.pc as i64 + 4 + offset as i64) as u32 & 0xFFFFFF;
179→                format!("brf     0x{:06X}", target)
180→            }
181→            Opcode::Brt => {
182→                let offset = self.imm8 as i8;
183→                let target = (self.pc as i64 + 4 + offset as i64) as u32 & 0xFFFFFF;
184→                format!("brt     0x{:06X}", target)
185→            }
186→            Opcode::Ceq => format!("ceq     {},{}", ra, rb),
187→            Opcode::Cls => format!("cls     {},{}", ra, rb),
188→            Opcode::Clu => format!("clu     {},{}", ra, rb),
189→            Opcode::Jal => format!("jal     {},({})", ra, rb),
190→            Opcode::Jmp => format!("jmp     ({})", ra),
191→            Opcode::La => format!("la      {},0x{:06X}", ra, self.imm24),
192→            Opcode::Lb => format!("lb      {},{}({})", ra, self.imm8 as i8, rb),
193→            Opcode::Lbu => format!("lbu     {},{}({})", ra, self.imm8, rb),
194→            Opcode::Lc => format!("lc      {},{}", ra, self.imm8 as i8),
195→            Opcode::Lcu => format!("lcu     {},{}", ra, self.imm8),
196→            Opcode::Lw => format!("lw      {},{}({})", ra, self.imm8 as i8, rb),
197→            Opcode::Mov => format!("mov     {},{}", ra, rb),
198→            Opcode::Mul => format!("mul     {},{}", ra, rb),
199→            Opcode::Or => format!("or      {},{}", ra, rb),
200→            Opcode::Pop => format!("pop     {}", ra),

1→//! COR24 instruction definitions — re-exported from cor24-isa.
2→
3→pub use cor24_isa::opcode::{DecodedInstruction, InstructionFormat, Opcode};
4→pub use cor24_isa::register::{REG_NAMES, reg_name};
