 50→#[cfg(test)]
 51→mod tests {
 52→    use super::*;
 53→
 54→    /// Helper to decode ROM value into opcode, ra, rb
 55→    fn decode(value: u16) -> (u8, u8, u8) {
 56→        let opcode = ((value >> 6) & 0x1F) as u8;
 57→        let ra = ((value >> 3) & 0x07) as u8;
 58→        let rb = (value & 0x07) as u8;
 59→        (opcode, ra, rb)
 60→    }
 61→
 62→    #[test]
 63→    fn test_valid_entry_count() {
 64→        let valid = DECODE_ROM.iter().filter(|&&v| v != 0xFFF).count();
 65→        assert_eq!(valid, VALID_ENTRY_COUNT, "Expected {} valid entries", VALID_ENTRY_COUNT);
 66→    }
 67→
 68→    #[test]
 69→    fn test_add_register_encodings() {
 70→        // add r0,r0 = 0x00 -> opcode=0, ra=0, rb=0
 71→        assert_eq!(decode(DECODE_ROM[0x00]), (0x00, 0, 0));
 72→        // add r0,r1 = 0x01 -> opcode=0, ra=0, rb=1
 73→        assert_eq!(decode(DECODE_ROM[0x01]), (0x00, 0, 1));
 74→        // add r1,r0 = 0x03 -> opcode=0, ra=1, rb=0
 75→        assert_eq!(decode(DECODE_ROM[0x03]), (0x00, 1, 0));
 76→    }
 77→
 78→    #[test]
 79→    fn test_branch_encodings() {
 80→        // bra = 0x13 -> opcode=3 (Bra)
 81→        assert_eq!(decode(DECODE_ROM[0x13]).0, 0x03);
 82→        // brf = 0x14 -> opcode=4 (Brf)
 83→        assert_eq!(decode(DECODE_ROM[0x14]).0, 0x04);
 84→        // brt = 0x15 -> opcode=5 (Brt)
 85→        assert_eq!(decode(DECODE_ROM[0x15]).0, 0x05);
