217→/// Ring buffer of recent instruction trace entries
218→#[derive(Clone)]
219→pub struct TraceBuffer {
220→    entries: Vec<TraceEntry>,
221→    head: usize,
222→    capacity: usize,
223→    count: usize,
224→}
225→
226→impl Default for TraceBuffer {
227→    fn default() -> Self {
228→        Self::new(200)
229→    }
230→}
231→
232→impl TraceBuffer {
233→    /// Create a new trace buffer with given capacity
234→    pub fn new(capacity: usize) -> Self {
235→        Self {
236→            entries: Vec::with_capacity(capacity),
237→            head: 0,
238→            capacity,
239→            count: 0,
240→        }
241→    }
242→
243→    /// Record a trace entry
244→    pub fn push(&mut self, entry: TraceEntry) {
245→        if self.entries.len() < self.capacity {
246→            self.entries.push(entry);
247→        } else {
248→            self.entries[self.head] = entry;
249→        }
250→        self.head = (self.head + 1) % self.capacity;
251→        self.count += 1;
252→    }
253→
254→    /// Get the last N entries in chronological order
255→    pub fn last_n(&self, n: usize) -> Vec<&TraceEntry> {
256→        let len = self.entries.len();
257→        let n = n.min(len);
258→        let mut result = Vec::with_capacity(n);
259→        for i in 0..n {
260→            let idx = if len < self.capacity {
261→                // Not yet wrapped
262→                len - n + i
263→            } else {
264→                (self.head + self.capacity - n + i) % self.capacity
265→            };
266→            result.push(&self.entries[idx]);
267→        }
268→        result
269→    }
270→
271→    /// Get all entries in chronological order
272→    pub fn all(&self) -> Vec<&TraceEntry> {
273→        self.last_n(self.entries.len())
274→    }
275→
276→    /// Total number of entries ever recorded
277→    pub fn total_count(&self) -> usize {
278→        self.count
279→    }
280→
281→    /// Number of entries currently in buffer
282→    pub fn len(&self) -> usize {
283→        self.entries.len()
284→    }
285→
286→    /// Check if buffer is empty
287→    pub fn is_empty(&self) -> bool {
288→        self.entries.is_empty()
289→    }
290→
291→    /// Clear all entries
292→    pub fn clear(&mut self) {
293→        self.entries.clear();
294→        self.head = 0;
295→        self.count = 0;
296→    }
297→
298→    /// Format the last N entries as a multi-line string
299→    pub fn format_last(&self, n: usize) -> String {
300→        let entries = self.last_n(n);
301→        let mut out = String::new();
302→        out.push_str(&format!("--- Trace (last {} of {} total) ---\n",
303→            entries.len(), self.count));
304→        out.push_str(&format!("{:>5} {:>8}  {:<24}  {}\n",
305→            "#", "PC", "Instruction", "Changes"));
306→        for entry in &entries {
307→            out.push_str(&format!("{}\n", entry));
308→        }
309→        out
310→    }
311→}
