313→/// COR24 CPU state
314→#[derive(Clone, Serialize, Deserialize)]
315→pub struct CpuState {
316→    /// Program counter (24-bit)
317→    pub pc: u32,
318→    /// Register file (8 x 24-bit registers)
319→    pub registers: [u32; 8],
320→    /// Condition flag (NOT carry — set by ceq/cls/clu, tested by brt/brf)
321→    pub c: bool,
322→    /// SRAM (1 MB, 0x000000-0x0FFFFF)
323→    pub memory: Vec<u8>,
324→    /// Embedded Block RAM (8 KB, mapped at 0xFEE000-0xFEFFFF)
325→    pub ebr: Vec<u8>,
326→    /// Halted flag
327→    pub halted: bool,
328→    /// Interrupt-in-service flag (prevents nested interrupts)
329→    pub intis: bool,
330→    /// Cycle count
331→    pub cycles: u64,
332→    /// Instruction count
333→    pub instructions: u64,
334→    /// I/O peripheral state
335→    pub io: IoState,
336→    /// Instruction execution trace (ring buffer, not serialized)
337→    #[serde(skip)]
338→    pub trace: TraceBuffer,
339→}
340→
341→impl Default for CpuState {
342→    fn default() -> Self {
343→        Self::new()
344→    }
345→}
346→
347→impl CpuState {
348→    /// Create a new CPU state with default values
349→    pub fn new() -> Self {
350→        let mut state = Self {
351→            pc: RESET_ADDRESS,
352→            registers: [0; 8],
353→            c: false,
354→            memory: vec![0; SRAM_SIZE],
355→            ebr: vec![0; EBR_SIZE],
356→            halted: false,
357→            intis: false,
358→            cycles: 0,
359→            instructions: 0,
360→            io: IoState::new(),
361→            trace: TraceBuffer::default(),
362→        };
363→        // Initialize stack pointer
364→        state.registers[4] = INITIAL_SP;
365→        state
366→    }
367→
368→    /// Reset CPU to initial state (preserves memory)
369→    pub fn reset(&mut self) {
370→        self.pc = RESET_ADDRESS;
371→        self.registers = [0; 8];
372→        self.registers[4] = INITIAL_SP;
373→        self.c = false;
374→        self.halted = false;
375→        self.intis = false;
376→        self.cycles = 0;
377→        self.instructions = 0;
378→        self.io = IoState::new();
379→        self.trace.clear();
380→    }
381→
382→    /// Hard reset (clears memory too)
383→    pub fn hard_reset(&mut self) {
384→        self.reset();
385→        self.memory.fill(0);
386→        self.ebr.fill(0);
387→    }
388→
389→    /// Check if address is in I/O region (0xFF0000-0xFFFFFF)
390→    fn is_io_addr(addr: u32) -> bool {
391→        (addr & 0xFF0000) == 0xFF0000
392→    }
393→
394→    /// Check if address is in EBR region (0xFEE000-0xFEFFFF)
395→    fn is_ebr_addr(addr: u32) -> bool {
396→        addr >= EBR_BASE && addr < EBR_BASE + EBR_SIZE as u32
397→    }
398→
399→    /// Read a byte from memory or I/O
400→    pub fn read_byte(&self, addr: u32) -> u8 {
401→        let addr = addr & 0xFFFFFF; // Mask to 24 bits
402→
403→        if Self::is_io_addr(addr) {
404→            self.read_io(addr)
405→        } else if Self::is_ebr_addr(addr) {
406→            self.ebr[(addr - EBR_BASE) as usize]
407→        } else if (addr as usize) < SRAM_SIZE {
408→            self.memory[addr as usize]
409→        } else {
410→            0 // Unmapped region
411→        }
412→    }
413→
414→    /// Write a byte to memory or I/O
415→    pub fn write_byte(&mut self, addr: u32, value: u8) {
416→        let addr = addr & 0xFFFFFF; // Mask to 24 bits
417→
418→        if Self::is_io_addr(addr) {
419→            self.write_io(addr, value);
420→        } else if Self::is_ebr_addr(addr) {
421→            self.ebr[(addr - EBR_BASE) as usize] = value;
422→        } else if (addr as usize) < SRAM_SIZE {
423→            self.memory[addr as usize] = value;
424→        }
425→        // Writes to unmapped regions are silently ignored
426→    }
427→
428→    /// Read from I/O register
429→    fn read_io(&self, addr: u32) -> u8 {
430→        match addr {
431→            IO_LEDSWDAT => self.io.switches,
432→            IO_INTENABLE => self.io.int_enable,
433→            IO_UARTDATA => self.io.uart_rx,
434→            IO_UARTSTAT => {
435→                let mut status = 0u8;
436→                if self.io.uart_rx_ready {
437→                    status |= 0x01; // Bit 0: RX data ready
438→                }
439→                // Bit 1: CTS active (always asserted in emulation)
440→                status |= 0x02;
441→                if self.io.uart_rx_overflow {
442→                    status |= 0x04; // Bit 2: RX overflow
443→                }
444→                if self.io.uart_tx_busy {
445→                    status |= 0x80; // Bit 7: TX busy
446→                }
447→                status
448→            }
449→            _ => 0, // Unknown I/O address
450→        }
451→    }
452→
453→    /// Read from I/O with side effects (auto-acknowledge)
454→    /// This is the version that should be called during execution.
455→    pub fn read_byte_exec(&mut self, addr: u32) -> u8 {
456→        let addr = addr & 0xFFFFFF;
457→        if addr == IO_UARTDATA {
458→            let data = self.io.uart_rx;
459→            self.io.uart_rx_ready = false; // Auto-acknowledge: reading data clears ready
460→            data
461→        } else {
462→            self.read_byte(addr)
463→        }
464→    }
465→
466→    /// Write to I/O register
467→    fn write_io(&mut self, addr: u32, value: u8) {
468→        match addr {
469→            IO_LEDSWDAT => {
470→                self.io.leds = value;
471→            }
472→            IO_INTENABLE => {
473→                self.io.int_enable = value;
474→            }
475→            IO_UARTDATA => {
476→                if self.io.uart_tx_busy {
477→                    // Write while busy — character dropped (hardware would ignore)
478→                    self.io.uart_tx_dropped += 1;
479→                } else {
480→                    self.io.uart_tx = value;
481→                    if value != 0 {
482→                        self.io.uart_output.push(value as char);
483→                    }
484→                    // TX busy for N cycles (simulates transmission time)
485→                    if self.io.uart_tx_busy_cycles > 0 {
486→                        self.io.uart_tx_busy = true;
487→                        self.io.uart_tx_countdown = self.io.uart_tx_busy_cycles;
488→                    }
489→                    // cycles=0 means instant ready (legacy/test mode)
490→                }
491→            }
492→            IO_UARTSTAT => {
493→                // Writing to status can clear overflow flag
494→                if value & 0x04 != 0 {
495→                    self.io.uart_rx_overflow = false;
496→                }
497→            }
498→            _ => {} // Ignore unknown I/O address
499→        }

490→                }
491→            }
492→            IO_UARTSTAT => {
493→                // Writing to status can clear overflow flag
494→                if value & 0x04 != 0 {
495→                    self.io.uart_rx_overflow = false;
496→                }
497→            }
498→            _ => {} // Ignore unknown I/O address
499→        }
500→    }
501→
502→    /// Tick UART timers — call after each instruction execution
503→    pub fn uart_tick(&mut self) {
504→        if self.io.uart_never_ready {
505→            // TX stays busy forever — tests that programs poll before writing
506→            return;
507→        }
508→        if self.io.uart_tx_countdown > 0 {
509→            self.io.uart_tx_countdown -= 1;
510→            if self.io.uart_tx_countdown == 0 {
511→                self.io.uart_tx_busy = false;
512→            }
513→        }
514→    }
515→
516→    /// Send a character to UART RX (simulates external input)
517→    pub fn uart_send_rx(&mut self, ch: u8) {
518→        if self.io.uart_rx_ready {
519→            self.io.uart_rx_overflow = true; // Previous data not read
520→        }
521→        self.io.uart_rx = ch;
522→        self.io.uart_rx_ready = true;
523→    }
524→
525→    /// Read a 24-bit word from memory (little-endian)
526→    pub fn read_word(&self, addr: u32) -> u32 {
527→        let b0 = self.read_byte(addr) as u32;
528→        let b1 = self.read_byte(addr.wrapping_add(1)) as u32;
529→        let b2 = self.read_byte(addr.wrapping_add(2)) as u32;
530→        b0 | (b1 << 8) | (b2 << 16)
531→    }
532→
533→    /// Write a 24-bit word to memory (little-endian)
534→    pub fn write_word(&mut self, addr: u32, value: u32) {
535→        self.write_byte(addr, (value & 0xFF) as u8);
536→        self.write_byte(addr.wrapping_add(1), ((value >> 8) & 0xFF) as u8);
537→        self.write_byte(addr.wrapping_add(2), ((value >> 16) & 0xFF) as u8);
538→    }
539→
540→    /// Get register value (masked to 24 bits)
541→    pub fn get_reg(&self, reg: u8) -> u32 {
542→        self.registers[(reg & 0x07) as usize] & 0xFFFFFF
543→    }
544→
545→    /// Set register value (masked to 24 bits)
546→    pub fn set_reg(&mut self, reg: u8, value: u32) {
547→        self.registers[(reg & 0x07) as usize] = value & 0xFFFFFF;
548→    }
549→
550→    /// Sign extend 8-bit to 24-bit
551→    pub fn sign_extend_8(value: u8) -> u32 {
552→        if value & 0x80 != 0 {
553→            0xFFFF00 | (value as u32)
554→        } else {
555→            value as u32
556→        }
557→    }
558→
559→    /// Check if an interrupt should fire
560→    /// Hardware: ireq = uart_rxrdy && ienab; irqis = ireq && !intis
561→    pub fn interrupt_pending(&self) -> bool {
