 77→    /// Assemble source code
 78→    pub fn assemble(&mut self, source: &str) -> AssemblyResult {
 79→        self.address = 0;
 80→        self.labels.clear();
 81→        self.forward_refs.clear();
 82→        self.output.clear();
 83→        self.lines.clear();
 84→        self.errors.clear();
 85→
 86→        // First pass: collect labels and emit code
 87→        for (line_num, line) in source.lines().enumerate() {
 88→            self.assemble_line(line, line_num);
 89→        }
 90→
 91→        // Second pass: resolve forward references
 92→        self.resolve_forward_refs();
 93→
 94→        // Update line bytes from resolved output
 95→        for line in &mut self.lines {
 96→            if !line.bytes.is_empty() {
 97→                let addr = line.address as usize;
 98→                let len = line.bytes.len();
 99→                if addr + len <= self.output.len() {
100→                    line.bytes = self.output[addr..addr + len].to_vec();
101→                }
102→            }
103→        }
104→
105→        AssemblyResult {
106→            bytes: self.output.clone(),
107→            lines: self.lines.clone(),
108→            errors: self.errors.clone(),
109→            labels: self.labels.clone(),
110→        }
111→    }
112→
113→    fn assemble_line(&mut self, line: &str, line_num: usize) {
114→        let line = line.trim();
115→
116→        // Skip empty lines and comments
117→        if line.is_empty() || line.starts_with(';') {
118→            return;
119→        }
120→
121→        // Strip trailing comments (semicolon only, matching reference as24)
122→        let line = if let Some(pos) = line.find(';') {
123→            line[..pos].trim()
124→        } else {
125→            line
126→        };
127→
128→        if line.is_empty() {
129→            return;
130→        }
131→
132→        let start_addr = self.address;
133→        let mut label = None;
134→        let mut instruction_part = line;
135→
136→        // Check for label (must be on its own line, matching reference as24)
137→        if let Some(colon_pos) = line.find(':') {
138→            let label_str = line[..colon_pos].trim();
139→            if !label_str.is_empty() {
140→                label = Some(label_str.to_string());
141→                self.labels.insert(label_str.to_string(), self.address);
142→            }
143→            instruction_part = line[colon_pos + 1..].trim();
144→            if !instruction_part.is_empty() {
145→                self.errors.push(format!(
146→                    "Line {}: label must be on its own line (as24 compatible)",
147→                    line_num + 1
148→                ));
149→                return;
150→            }
151→        }
152→
153→        // Handle directives
154→        if instruction_part.starts_with('.') {
155→            let before_len = self.output.len();
156→            self.handle_directive(instruction_part, line_num);
157→            // Record directive bytes in lines so they appear in output
158→            let directive_bytes = self.output[before_len..].to_vec();
159→            if !directive_bytes.is_empty() || label.is_some() {
160→                self.lines.push(AssembledLine {
161→                    address: start_addr,
162→                    bytes: directive_bytes,
163→                    source: line.to_string(),
164→                    label,
165→                });
166→            }
167→            return;
168→        }
169→
170→        // Skip if no instruction
171→        if instruction_part.is_empty() {
172→            if label.is_some() {
173→                self.lines.push(AssembledLine {
174→                    address: start_addr,
175→                    bytes: vec![],
176→                    source: line.to_string(),
177→                    label,
178→                });
179→            }
180→            return;
181→        }
182→
183→        // Parse instruction
184→        let bytes = self.parse_instruction(instruction_part, line_num);
185→
186→        self.lines.push(AssembledLine {
187→            address: start_addr,
188→            bytes: bytes.clone(),
189→            source: line.to_string(),
190→            label,
191→        });
192→
193→        for b in bytes {
194→            self.output.push(b);
195→            self.address += 1;
196→        }
197→    }
198→
199→    fn handle_directive(&mut self, directive: &str, _line_num: usize) {
200→        let parts: Vec<&str> = directive.split_whitespace().collect();
201→        if parts.is_empty() {
202→            return;
203→        }
204→
205→        match parts[0].to_lowercase().as_str() {
206→            ".org" => {
207→                if parts.len() > 1
208→                    && let Some(addr) = self.parse_number(parts[1])
209→                {
210→                    // Pad output to reach the new address
211→                    while self.output.len() < addr as usize {
212→                        self.output.push(0);
213→                    }
214→                    self.address = addr;
215→                }
216→            }
217→            ".byte" => {
218→                for part in &parts[1..] {
219→                    for token in part.split(',') {
220→                        let token = token.trim();
221→                        if token.is_empty() {
222→                            continue;
223→                        }
224→                        if let Some(val) = self.parse_number(token) {
225→                            self.output.push(val as u8);
226→                            self.address += 1;
227→                        }
228→                    }
229→                }
230→            }
231→            ".word" => {
232→                for part in &parts[1..] {
233→                    for token in part.split(',') {
234→                        let token = token.trim();
235→                        if token.is_empty() {
236→                            continue;
237→                        }
238→                        if let Some(val) = self.parse_number(token) {
239→                            // 24-bit word, little-endian
240→                            self.output.push((val & 0xFF) as u8);
241→                            self.output.push(((val >> 8) & 0xFF) as u8);
242→                            self.output.push(((val >> 16) & 0xFF) as u8);
243→                            self.address += 3;
244→                        }
245→                    }
246→                }
247→            }
248→            // .ascii and .asciz not supported by reference as24
249→            ".comm" => {
250→                // BSS allocation: .comm symbol, size
251→                // Defines label at current address and advances by size
252→                // No bytes emitted (memory is zero-initialized)
253→                if parts.len() >= 3 {
254→                    let sym = parts[1].trim_matches(',');
255→                    if let Some(size) = self.parse_number(parts[2].trim_matches(',')) {
256→                        self.labels.insert(sym.to_string(), self.address);
257→                        self.address += size;
258→                    }
259→                }
260→            }
261→            // Directives that are safe to ignore in flat memory model
262→            ".text" | ".data" | ".globl" | ".global" | ".section" | ".align" => {}
263→            _ => {}
264→        }
265→    }
