267→    fn parse_instruction(&mut self, inst: &str, line_num: usize) -> Vec<u8> {
268→        // Strip trailing comments
269→        let inst = if let Some(pos) = inst.find(';') {
270→            &inst[..pos]
271→        } else if let Some(pos) = inst.find('#') {
272→            &inst[..pos]
273→        } else {
274→            inst
275→        };
276→
277→        let parts: Vec<&str> = inst.split_whitespace().collect();
278→        if parts.is_empty() {
279→            return vec![];
280→        }
281→
282→        let mnemonic = parts[0].to_lowercase();
283→        let operands_str = if parts.len() > 1 {
284→            parts[1..].join(" ")
285→        } else {
286→            String::new()
287→        };
288→        let operands: Vec<&str> = if !operands_str.is_empty() {
289→            operands_str.split(',').map(|s| s.trim()).collect()
290→        } else {
291→            vec![]
292→        };
293→
294→        match mnemonic.as_str() {
295→            // Stack operations
296→            "push" => self.encode_push(&operands, line_num),
297→            "pop" => self.encode_pop(&operands, line_num),
298→
299→            // Move operations
300→            "mov" => self.encode_mov(&operands, line_num),
301→
302→            // Arithmetic
303→            "add" => self.encode_add(&operands, line_num),
304→            "sub" => self.encode_sub(&operands, line_num),
305→            "mul" => self.encode_mul(&operands, line_num),
306→
307→            // Logic
308→            "and" => self.encode_alu(&operands, Opcode::And, "and", line_num),
309→            "or" => self.encode_alu(&operands, Opcode::Or, "or", line_num),
310→            "xor" => self.encode_alu(&operands, Opcode::Xor, "xor", line_num),
311→
312→            // Shifts
313→            "shl" => self.encode_alu(&operands, Opcode::Shl, "shl", line_num),
314→            "sra" => self.encode_alu(&operands, Opcode::Sra, "sra", line_num),
315→            "srl" => self.encode_alu(&operands, Opcode::Srl, "srl", line_num),
316→
317→            // Compares
318→            "ceq" => self.encode_alu(&operands, Opcode::Ceq, "ceq", line_num),
319→            "cls" => self.encode_alu(&operands, Opcode::Cls, "cls", line_num),
320→            "clu" => self.encode_alu(&operands, Opcode::Clu, "clu", line_num),
321→
322→            // Branches
323→            "bra" => self.encode_branch(&operands, Opcode::Bra, line_num),
324→            "brf" => self.encode_branch(&operands, Opcode::Brf, line_num),
325→            "brt" => self.encode_branch(&operands, Opcode::Brt, line_num),
326→
327→            // Jumps
328→            "jmp" => self.encode_jmp(&operands, line_num),
329→            "jal" => self.encode_jal(&operands, line_num),
330→
331→            // Load operations
332→            "la" => self.encode_la(&operands, line_num),
333→            "lc" => self.encode_lc(&operands, false, line_num),
334→            "lcu" => self.encode_lc(&operands, true, line_num),
335→            "lb" => self.encode_load_store(&operands, Opcode::Lb, "lb", line_num),
336→            "lbu" => self.encode_load_store(&operands, Opcode::Lbu, "lbu", line_num),
337→            "lw" => self.encode_load_store(&operands, Opcode::Lw, "lw", line_num),
338→
339→            // Store operations
340→            "sb" => self.encode_load_store(&operands, Opcode::Sb, "sb", line_num),
341→            "sw" => self.encode_load_store(&operands, Opcode::Sw, "sw", line_num),
342→
343→            // Extensions
344→            "sxt" => self.encode_alu(&operands, Opcode::Sxt, "sxt", line_num),
345→            "zxt" => self.encode_alu(&operands, Opcode::Zxt, "zxt", line_num),
346→
347→            // Pseudo-instructions
348→            "nop" => vec![0xFF],
349→
350→            _ => {
351→                self.errors.push(format!(
352→                    "Line {}: Unknown instruction '{}'",
353→                    line_num + 1,
354→                    mnemonic
355→                ));
356→                vec![]
357→            }
358→        }
359→    }
