361→    fn parse_register(&self, s: &str) -> Option<u8> {
362→        let s = s.trim().to_lowercase();
363→        match s.as_str() {
364→            "r0" => Some(0),
365→            "r1" => Some(1),
366→            "r2" => Some(2),
367→            "fp" => Some(3),
368→            "sp" => Some(4),
369→            "z" | "c" => Some(5), // z=zero for comparisons, c=condition flag for mov
370→            "iv" => Some(6),
371→            "ir" => Some(7),
372→            _ => None,
