376→    fn parse_number(&self, s: &str) -> Option<u32> {
377→        let s = s.trim();
378→        if (s.ends_with('h') || s.ends_with('H'))
379→            && s.len() > 1
380→            && s.as_bytes()[0].is_ascii_hexdigit()
381→        {
382→            // Intel-style hex: 0FFh, 2Ah (must start with digit)
383→            u32::from_str_radix(&s[..s.len() - 1], 16).ok()
384→        } else if s.starts_with('-') {
385→            s.parse::<i32>().ok().map(|v| v as u32)
386→        } else {
387→            s.parse::<u32>().ok()
388→        }
389→    }
