611→    /// Generic ALU instruction encoding (and, or, xor, shifts, compares, etc.)
612→    fn encode_alu(
613→        &mut self,
614→        operands: &[&str],
615→        opcode: Opcode,
616→        mnemonic: &str,
617→        line_num: usize,
618→    ) -> Vec<u8> {
619→        if operands.len() < 2 {
620→            self.errors.push(format!(
621→                "Line {}: {} requires two operands",
622→                line_num + 1,
623→                mnemonic
624→            ));
625→            return vec![];
626→        }
627→
628→        let ra = self.parse_register(operands[0]);
629→        let rb = self.parse_register(operands[1]);
630→
631→        match (ra, rb) {
632→            (Some(ra), Some(rb)) => {
633→                if let Some(byte) = encode::encode_instruction(opcode, ra, rb) {
634→                    vec![byte]
635→                } else {
636→                    self.errors.push(format!(
637→                        "Line {}: {} {},{} not supported",
638→                        line_num + 1,
639→                        mnemonic,
640→                        operands[0],
641→                        operands[1]
642→                    ));
643→                    vec![]
644→                }
645→            }
646→            _ => {
647→                self.errors.push(format!(
