657→    fn encode_branch(&mut self, operands: &[&str], opcode: Opcode, line_num: usize) -> Vec<u8> {
658→        if operands.is_empty() {
659→            self.errors
660→                .push(format!("Line {}: branch requires target", line_num + 1));
661→            return vec![];
662→        }
663→
664→        let target = operands[0].trim();
665→        let first_byte = encode::encode_branch(opcode).unwrap_or(0x13);
666→
667→        // Check if it's a label
668→        if let Some(&addr) = self.labels.get(target) {
669→            // Calculate relative offset: COR24 pipeline means branch base = instr_addr + 4
670→            let branch_base = self.address + 4;
671→            let offset = (addr as i32) - (branch_base as i32);
672→            if !(-128..=127).contains(&offset) {
673→                self.errors
674→                    .push(format!("Line {}: Branch target too far", line_num + 1));
675→                return vec![];
676→            }
677→            vec![first_byte, offset as u8]
678→        } else if let Some(imm) = self.parse_number(target) {
679→            // Direct offset
680→            vec![first_byte, imm as u8]
681→        } else {
682→            // Forward reference
683→            self.forward_refs.push(ForwardRef {
684→                address: self.address + 1,
685→                label: target.to_string(),
686→                ref_type: RefType::Relative8,
687→                line_num,
688→            });
689→            vec![first_byte, 0x00] // Placeholder
690→        }
691→    }
692→
693→    fn encode_jmp(&mut self, operands: &[&str], line_num: usize) -> Vec<u8> {
694→        if operands.is_empty() {
695→            self.errors
696→                .push(format!("Line {}: jmp requires target", line_num + 1));
697→            return vec![];
698→        }
699→
700→        let target = operands[0].trim();
701→
702→        // Check for (ra) syntax - indirect jump
703→        if target.starts_with('(') && target.ends_with(')') {
704→            let reg = &target[1..target.len() - 1];
705→            if let Some(ra) = self.parse_register(reg) {
706→                if let Some(byte) = encode::encode_jmp(ra) {
707→                    return vec![byte];
708→                } else {
709→                    self.errors.push(format!(
710→                        "Line {}: jmp ({}) not supported",
711→                        line_num + 1,
712→                        reg
713→                    ));
714→                    return vec![];
715→                }
716→            }
717→        }
718→
719→        self.errors
720→            .push(format!("Line {}: Invalid jmp syntax", line_num + 1));
721→        vec![]
722→    }
723→
724→    fn encode_jal(&mut self, operands: &[&str], line_num: usize) -> Vec<u8> {
725→        if operands.len() < 2 {
726→            self.errors
727→                .push(format!("Line {}: jal requires ra,(rb)", line_num + 1));
728→            return vec![];
729→        }
730→
731→        let ra = self.parse_register(operands[0]);
732→        let rb_str = operands[1].trim();
733→
734→        // Parse (rb) syntax
735→        if rb_str.starts_with('(') && rb_str.ends_with(')') {
736→            let reg = &rb_str[1..rb_str.len() - 1];
737→            if let (Some(ra), Some(rb)) = (ra, self.parse_register(reg)) {
738→                if let Some(byte) = encode::encode_jal(ra, rb) {
739→                    return vec![byte];
740→                } else {
741→                    self.errors.push(format!(
742→                        "Line {}: jal {},({}) not supported",
743→                        line_num + 1,
744→                        operands[0],
745→                        reg
746→                    ));
747→                    return vec![];
748→                }
749→            }
750→        }
751→
752→        self.errors
753→            .push(format!("Line {}: Invalid jal syntax", line_num + 1));
754→        vec![]
755→    }
756→
757→    fn encode_la(&mut self, operands: &[&str], line_num: usize) -> Vec<u8> {
758→        if operands.len() < 2 {
759→            self.errors.push(format!(
760→                "Line {}: la requires register and address",
761→                line_num + 1
762→            ));
763→            return vec![];
764→        }
765→
766→        let ra = self.parse_register(operands[0]);
767→        let target = operands[1].trim();
768→
769→        if let Some(ra) = ra {
770→            if let Some(first_byte) = encode::encode_la(ra) {
771→                if let Some(addr) = self.parse_number(target) {
772→                    // Immediate address
773→                    return vec![
774→                        first_byte,
775→                        (addr & 0xFF) as u8,
776→                        ((addr >> 8) & 0xFF) as u8,
777→                        ((addr >> 16) & 0xFF) as u8,
778→                    ];
779→                } else if let Some(&addr) = self.labels.get(target) {
780→                    // Known label
781→                    return vec![
782→                        first_byte,
783→                        (addr & 0xFF) as u8,
784→                        ((addr >> 8) & 0xFF) as u8,
785→                        ((addr >> 16) & 0xFF) as u8,
786→                    ];
787→                } else {
788→                    // Forward reference
789→                    self.forward_refs.push(ForwardRef {
790→                        address: self.address + 1,
791→                        label: target.to_string(),
792→                        ref_type: RefType::Absolute24,
793→                        line_num,
794→                    });
795→                    return vec![first_byte, 0x00, 0x00, 0x00];
796→                }
797→            } else {
798→                self.errors.push(format!(
799→                    "Line {}: la {} not supported",
800→                    line_num + 1,
801→                    operands[0]
802→                ));
803→                return vec![];
804→            }
805→        }
806→
807→        self.errors
808→            .push(format!("Line {}: Invalid la operand", line_num + 1));
809→        vec![]
810→    }
811→
812→    fn encode_lc(&mut self, operands: &[&str], unsigned: bool, line_num: usize) -> Vec<u8> {
813→        if operands.len() < 2 {
814→            self.errors.push(format!(
815→                "Line {}: lc requires register and constant",
816→                line_num + 1
817→            ));
818→            return vec![];
819→        }
820→
821→        let ra = self.parse_register(operands[0]);
822→        let imm = self.parse_number(operands[1]);
823→
824→        match (ra, imm) {
825→            (Some(ra), Some(imm)) => {
826→                // lc sign-extends an 8-bit immediate: valid range is 0..=127
827→                // (values 128..=255 get sign-extended to large negative numbers)
828→                if !unsigned && imm > 127 && imm < 0xFFFFFF80 {
829→                    self.errors.push(format!(
830→                        "Line {}: lc immediate {} out of range (0..127 or use lcu for unsigned)",
831→                        line_num + 1, imm
832→                    ));
833→                    return vec![];
834→                }
835→                if unsigned && imm > 255 {
836→                    self.errors.push(format!(
837→                        "Line {}: lcu immediate {} out of range (0..255)",
838→                        line_num + 1, imm
839→                    ));
840→                    return vec![];
841→                }
842→                if let Some(first_byte) = encode::encode_lc(ra, unsigned) {
843→                    vec![first_byte, imm as u8]
844→                } else {
845→                    let mnemonic = if unsigned { "lcu" } else { "lc" };
846→                    self.errors.push(format!(
847→                        "Line {}: {} {} not supported",
848→                        line_num + 1,
849→                        mnemonic,
850→                        operands[0]
851→                    ));
852→                    vec![]
853→                }
854→            }
855→            _ => {
856→                self.errors
857→                    .push(format!("Line {}: Invalid lc operands", line_num + 1));
858→                vec![]
859→            }
860→        }
861→    }
862→
863→    fn encode_load_store(
864→        &mut self,
865→        operands: &[&str],
866→        opcode: Opcode,
867→        mnemonic: &str,
868→        line_num: usize,
869→    ) -> Vec<u8> {
870→        if operands.len() < 2 {
871→            self.errors.push(format!(
872→                "Line {}: {} requires operands",
873→                line_num + 1,
874→                mnemonic
875→            ));
876→            return vec![];
877→        }
878→
879→        let ra = self.parse_register(operands[0]);
880→        let addr_part = operands[1].trim();
881→
882→        // Parse offset(rb) syntax
883→        if let Some(paren_pos) = addr_part.find('(') {
884→            let offset_str = &addr_part[..paren_pos];
885→            let rb_str = &addr_part[paren_pos + 1..].trim_end_matches(')');
886→
887→            let offset = if offset_str.is_empty() {
888→                Some(0)
889→            } else {
890→                self.parse_number(offset_str)
891→            };
892→            let rb = self.parse_register(rb_str);
893→
894→            if let (Some(ra), Some(rb), Some(offset)) = (ra, rb, offset) {
895→                if let Some(first_byte) = encode::encode_load_store(opcode, ra, rb) {
896→                    return vec![first_byte, offset as u8];
897→                } else {
898→                    self.errors.push(format!(
899→                        "Line {}: {} {},{} not supported",
900→                        line_num + 1,
901→                        mnemonic,
902→                        operands[0],
903→                        operands[1]
904→                    ));
905→                    return vec![];
906→                }
907→            }
908→        }
909→
910→        self.errors.push(format!(
911→            "Line {}: Invalid {} syntax",
912→            line_num + 1,
913→            mnemonic
914→        ));
915→        vec![]
916→    }
917→
918→    fn resolve_forward_refs(&mut self) {
919→        for fref in &self.forward_refs {
920→            if let Some(&target_addr) = self.labels.get(&fref.label) {
921→                match fref.ref_type {
922→                    RefType::Absolute24 => {
923→                        let addr = fref.address as usize;
924→                        if addr + 2 < self.output.len() {
925→                            self.output[addr] = (target_addr & 0xFF) as u8;
926→                            self.output[addr + 1] = ((target_addr >> 8) & 0xFF) as u8;
927→                            self.output[addr + 2] = ((target_addr >> 16) & 0xFF) as u8;
928→                        }
929→                    }
930→                    RefType::Relative8 => {
931→                        // fref.address is the offset byte (instr_addr + 1)
932→                        // branch_base = instr_addr + 4 = fref.address + 3
933→                        let branch_base = fref.address + 3;
934→                        let offset = (target_addr as i32) - (branch_base as i32);
935→                        if (-128..=127).contains(&offset) {
936→                            let addr = fref.address as usize;
937→                            if addr < self.output.len() {
938→                                self.output[addr] = offset as u8;
939→                            }
940→                        } else {
941→                            self.errors.push(format!(
942→                                "Line {}: Branch target '{}' too far",
943→                                fref.line_num + 1,
944→                                fref.label
945→                            ));
946→                        }
947→                    }
948→                }
949→            } else {
950→                self.errors.push(format!(
951→                    "Line {}: Undefined label '{}'",
952→                    fref.line_num + 1,
953→                    fref.label
954→                ));
955→            }
956→        }
957→    }
958→}
