1168→        use crate::cpu::{CpuState, Executor};
1169→
1170→        // Count down from 3 to 0 using branch loop:
1171→        //   lc r0,3          ; r0 = 3
1172→        // loop:
1173→        //   add r0,-1        ; r0 -= 1  (add imm with sign-extended 0xFF = -1)
1174→        //   ceq r0,z         ; compare r0 to zero
1175→        //   brf loop         ; if not equal, loop
1176→        let code = "lc r0,3\nloop:\nadd r0,-1\nceq r0,z\nbrf loop";
1177→        let mut asm = Assembler::new();
1178→        let result = asm.assemble(code);
1179→        assert!(result.errors.is_empty(), "Assembly errors: {:?}", result.errors);
1180→
1181→        let mut cpu = CpuState::new();
1182→        cpu.load_program(0, &result.bytes);
1183→        let executor = Executor::new();
1184→
1185→        // Should run: lc, then 3 iterations of (add, ceq, brf), then fall through
1186→        // = 1 + 3*3 = 10 instructions, but brf not taken on last = still 10
1187→        executor.run(&mut cpu, 100);
1188→
1189→        assert_eq!(cpu.get_reg(0), 0, "r0 should be 0 after counting down");
1190→        assert!(cpu.c, "c flag should be true (r0 == z)");
1191→    }
